    var strength = GetFloat(parameters, "intensity", 2f);
    var channel = GetChoice(parameters, "channel", "luminance");
    var flipX = GetBool(parameters, "flipX", false);
    var flipY = GetBool(parameters, "flipY", false);

    var size = context.TileSize;
    var output = new PixelBuffer(size, size);

    // Override strength from float input
    if (inputs.Length > 1 && inputs[1] != null)
    {
        var (r, _, _, _) = inputs[1]!.GetPixel(0, 0);
        strength = r * 10f;
    }

    output.ParallelForEachPixel((x, y) =>
    {
        // Sample height at neighboring pixels
        var hL = SampleHeight(input, x - 1, y, channel);
        var hR = SampleHeight(input, x + 1, y, channel);
        var hD = SampleHeight(input, x, y - 1, channel);
        var hU = SampleHeight(input, x, y + 1, channel);
        var hC = SampleHeight(input, x, y, channel);

        // Sobel gradients
        var gx = (hR - hL) * strength * 0.5f;
        var gy = (hD - hU) * strength * 0.5f;

        if (flipX) gx = -gx;
        if (flipY) gy = -gy;

        // Normalize
        var length = MathF.Sqrt(gx * gx + gy * gy + 1f);
        var nx = gx / length;
        var ny = gy / length;
        var nz = 1f / length;

        // Encode normal in RGB
        var rVal = nx * 0.5f + 0.5f;
        var gVal = ny * 0.5f + 0.5f;
        var bVal = nz * 0.5f + 0.5f;

        output.SetPixel(x, y, rVal, gVal, bVal, 1f);
    });

    return output;

private static float SampleHeight(PixelBuffer buffer, int x, int y, string channel)
{
    x = Math.Clamp(x, 0, buffer.Width - 1);
    y = Math.Clamp(y, 0, buffer.Height - 1);
    var (r, g, b, a) = buffer.GetPixel(x, y);

    return channel switch
    {
        "red" => r,
        "green" => g,
        "blue" => b,
        "alpha" => a,
        _ => r * 0.299f + g * 0.587f + b * 0.114f // luminance
    };
    }
}
